import React, { useState, useEffect, useCallback } from 'react';
import { studentAPI, schoolAPI } from '../services/api';

const THEMES = {
  indigo:  { name:'Deep Indigo',  p1:'#1E1B4B', p2:'#3730A3', acc:'#818CF8', bg:'#EEF2FF' },
  emerald: { name:'Emerald',      p1:'#064E3B', p2:'#047857', acc:'#34D399', bg:'#ECFDF5' },
  crimson: { name:'Crimson',      p1:'#7F1D1D', p2:'#991B1B', acc:'#FCA5A5', bg:'#FEF2F2' },
  violet:  { name:'Violet',       p1:'#4C1D95', p2:'#6D28D9', acc:'#C4B5FD', bg:'#F5F3FF' },
  teal:    { name:'Ocean Teal',   p1:'#134E4A', p2:'#0F766E', acc:'#5EEAD4', bg:'#F0FDFA' },
  slate:   { name:'Slate Pro',    p1:'#0F172A', p2:'#1E293B', acc:'#94A3B8', bg:'#F8FAFC' },
};

const fmt = d => d ? String(d).split('T')[0] : '—';

function Logo({ sch, size, dark }) {
  if (sch?.logo) return (
    <img src={sch.logo} alt="logo"
      style={{ width:size, height:size, objectFit:'contain', borderRadius:4,
        filter: dark ? 'brightness(0) invert(1)' : 'none' }}
      onError={e => { e.target.style.display='none'; }}
    />
  );
  return (
    <svg width={size} height={size} viewBox="0 0 32 32" fill="none">
      <rect width="32" height="32" rx="6" fill={dark ? 'rgba(255,255,255,.15)' : 'rgba(255,255,255,.9)'}/>
      <path d="M8 8h16M8 16h10M8 24h13" stroke={dark ? 'rgba(255,255,255,.7)' : '#374151'} strokeWidth="2.5" strokeLinecap="round"/>
    </svg>
  );
}

function Photo({ stu, w, h, radius, border, fallbackColor }) {
  const initials = ((stu?.first_name||'')[0]||'') + ((stu?.last_name||'')[0]||'');
  return (
    <div style={{ width:w, height:h, borderRadius:radius, overflow:'hidden',
      border:border||'none', background:fallbackColor||'rgba(255,255,255,.1)',
      display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
      {stu?.photo_url
        ? <img src={stu.photo_url} alt="photo"
            style={{ width:'100%', height:'100%', objectFit:'cover' }}
            onError={e => { e.target.style.display='none'; }}
          />
        : <span style={{ fontSize:Math.floor(w*0.38), fontWeight:800,
            color: fallbackColor?.includes('EEF')||fallbackColor?.includes('ECF')||fallbackColor?.includes('F5F')||fallbackColor?.includes('F0F')||fallbackColor?.includes('F8F') ? '#374151' : 'rgba(255,255,255,.3)',
            fontFamily:'Arial,sans-serif', userSelect:'none' }}>
            {initials.toUpperCase()||'?'}
          </span>
      }
    </div>
  );
}

function Barcode() {
  return (
    <div style={{ display:'flex', gap:2, alignItems:'flex-end' }}>
      {[3,1,4,1,3,2,1,3,2,1,4,1].map((h,i)=>(
        <div key={i} style={{ width:2, height:h*4, background:'rgba(255,255,255,.35)', borderRadius:1 }}/>
      ))}
    </div>
  );
}

// ── H1: Classic Split ──────────────────────────────────────────
function H1({ stu, th, sch }) {
  const t = THEMES[th]||THEMES.indigo;
  const name = ((stu?.first_name||'')+' '+(stu?.last_name||'')).trim()||'Student Name';
  return (
    <div style={{ width:340, height:214, borderRadius:16, overflow:'hidden', display:'flex', background:'#fff', border:'1px solid #E5E7EB', fontFamily:'"Segoe UI",Arial,sans-serif', flexShrink:0 }}>
      {/* Left sidebar */}
      <div style={{ width:96, background:t.p1, display:'flex', flexDirection:'column', alignItems:'center', padding:'12px 0 10px', gap:9, flexShrink:0 }}>
        <div style={{ width:40, height:40, borderRadius:8, background:'rgba(255,255,255,.12)', border:'1.5px solid rgba(255,255,255,.22)', display:'flex', alignItems:'center', justifyContent:'center', overflow:'hidden' }}>
          <Logo sch={sch} size={34} dark/>
