  :'<svg width="20" height="20" viewBox="0 0 32 32" fill="none"><rect width="32" height="32" rx="6" fill="rgba(255,255,255,.15)"/><path d="M8 8h16M8 16h10M8 24h13" stroke="rgba(255,255,255,.7)" stroke-width="2.5" stroke-linecap="round"/></svg>';
function photo(s,w,h,r,border,fbg){
  var inner=s.photo_url
    ?'<img src="'+s.photo_url+'" style="width:100%;height:100%;object-fit:cover" onerror="this.style.display=\'none\'">'
    :'<span style="font-size:'+(w*.38)+'px;font-weight:800;color:rgba(255,255,255,.3);font-family:Arial;">'+initials(s)+'</span>';
  return '<div style="width:'+w+'px;height:'+h+'px;border-radius:'+r+';overflow:hidden;border:'+border+';background:'+fbg+';display:flex;align-items:center;justify-content:center;flex-shrink:0;">'+inner+'</div>';
}
function barcode(){return '<div style="display:flex;gap:2px;align-items:flex-end;">'
  +[3,1,4,1,3,2,1,3,2,1].map(function(h){return '<div style="width:2px;height:'+(h*4)+'px;background:rgba(255,255,255,.35);border-radius:1px;"></div>';}).join('')+'</div>';}
S.forEach(function(s){
  var nm=((s.first_name||'')+' '+(s.last_name||'')).trim()||'Student Name';
  var d=document.createElement('div');d.style.cssText='flex-shrink:0;break-inside:avoid;';
  var html=${isV?`'<div style="width:210px;height:326px;border-radius:16px;overflow:hidden;background:#fff;border:1px solid #E5E7EB;font-family:Segoe UI,Arial,sans-serif;display:flex;flex-direction:column;">'
  +'<div style="background:'+T.p1+';padding:10px 12px;display:flex;align-items:center;gap:8px;flex-shrink:0;">'
  +'<div style="width:30px;height:30px;border-radius:6px;background:rgba(255,255,255,.12);border:1.5px solid rgba(255,255,255,.22);display:flex;align-items:center;justify-content:center;overflow:hidden;flex-shrink:0;">'+logo+'</div>'
  +'<div><div style="font-size:9.5px;font-weight:800;color:#fff;">'+SCH.schoolName+'</div><div style="font-size:6px;color:rgba(255,255,255,.5);">STUDENT IDENTITY CARD</div></div>'
  +'</div>'
  +'<div style="padding:12px 0 6px;display:flex;justify-content:center;">'+photo(s,76,84,'12px','3px solid '+T.p1,T.bg)+'</div>'
  +'<div style="text-align:center;padding:0 10px 8px;">'
  +'<div style="font-size:13.5px;font-weight:800;color:#111827;">'+nm+'</div>'
  +'<div style="font-size:9px;color:'+T.p1+';font-weight:700;margin-top:3px;">'+(s.class_name||'—')+(s.section_name?' · Sec '+s.section_name:'')+'</div>'
  +'</div>'
  +'<div style="flex:1;padding:0 12px;display:flex;flex-direction:column;gap:4px;">'
  +[["Adm No.",s.admission_no||"—"],["Roll No.",s.roll_no||"—"],["Date of Birth",fmt(s.date_of_birth)],["Blood Group",s.blood_group||"—"],["Parent",s.parent_name||"—"],["Contact",s.parent_phone||"—"]].map(function(r){
    return '<div style="display:flex;justify-content:space-between;align-items:center;border-bottom:0.5px solid #F3F4F6;padding-bottom:3px;"><span style="font-size:7.5px;color:#9CA3AF;font-weight:700;">'+r[0]+'</span><span style="font-size:8.5px;font-weight:700;color:#111827;max-width:108px;text-align:right;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">'+r[1]+'</span></div>';
  }).join('')
  +'</div>'
  +'<div style="background:'+T.bg+';padding:7px 12px;display:flex;justify-content:space-between;align-items:center;flex-shrink:0;">'
  +'<div style="font-size:6.5px;color:'+T.p1+';font-weight:600;">Valid: '+yr+'–'+(yr+1)+'</div>'
  +'<div style="text-align:center;"><div style="width:54px;border-bottom:1px solid '+T.p1+';margin-bottom:2px;"></div><div style="font-size:6.5px;font-weight:700;color:'+T.p1+';">PRINCIPAL</div></div>'
  +'</div></div>';`
  :`'<div style="width:340px;height:214px;border-radius:16px;overflow:hidden;display:flex;background:#fff;border:1px solid #E5E7EB;font-family:Segoe UI,Arial,sans-serif;">'
  +'<div style="width:96px;background:'+T.p1+';display:flex;flex-direction:column;align-items:center;padding:12px 0 10px;gap:9px;flex-shrink:0;">'
  +'<div style="width:40px;height:40px;border-radius:8px;background:rgba(255,255,255,.12);border:1.5px solid rgba(255,255,255,.22);display:flex;align-items:center;justify-content:center;overflow:hidden;">'+logo+'</div>'
  +photo(s,68,74,'10px','2.5px solid rgba(255,255,255,.3)','rgba(255,255,255,.08)')
  +barcode()
  +'</div>'
  +'<div style="flex:1;padding:11px 13px;display:flex;flex-direction:column;justify-content:space-between;">'
  +'<div>'
  +'<div style="font-size:7px;font-weight:700;color:'+T.p2+';text-transform:uppercase;letter-spacing:.1em;margin-bottom:1px;">'+SCH.schoolName+'</div>'
  +'<div style="font-size:6px;color:#9CA3AF;margin-bottom:6px;">Student Identity Card</div>'
  +'<div style="font-size:15px;font-weight:800;color:#111827;line-height:1.2;margin-bottom:8px;">'+nm+'</div>'
  +'<div style="display:grid;grid-template-columns:1fr 1fr;row-gap:4px;column-gap:8px;">'
  +[["Class",s.class_name||"—"],["Section",s.section_name||"—"],["Adm No.",s.admission_no||"—"],["Roll No.",s.roll_no||"—"],["D.O.B.",fmt(s.date_of_birth)],["Blood",s.blood_group||"—"]].map(function(r){
    return '<div><div style="font-size:7px;font-weight:700;color:#9CA3AF;text-transform:uppercase;">'+r[0]+'</div><div style="font-size:9.5px;font-weight:700;color:#111827;">'+r[1]+'</div></div>';
  }).join('')
  +'</div>'+(s.parent_name?'<div style="font-size:8px;color:#6B7280;margin-top:5px;">Parent: <strong style="color:#374151;">'+s.parent_name+'</strong>'+(s.parent_phone?' · '+s.parent_phone:'')+'</div>':'')
  +'</div>'
  +'<div style="border-top:1.5px solid '+T.bg+';padding-top:5px;display:flex;justify-content:space-between;align-items:flex-end;">'
  +'<div style="font-size:6.5px;color:#9CA3AF;">Valid: '+yr+'–'+(yr+1)+'</div>'
  +'<div style="text-align:center;"><div style="width:52px;border-bottom:1px solid '+T.p1+';margin-bottom:2px;"></div><div style="font-size:7px;color:'+T.p1+';font-weight:700;">PRINCIPAL</div></div>'
  +'</div></div></div>';`};
  d.innerHTML=html;document.getElementById('g').appendChild(d);
});
<\/script></body></html>`);
  win.document.close();
}

export default function IDCard() {
  const [students,    setStudents]    = useState([]);
  const [search,      setSearch]      = useState('');
  const [filterClass, setFilterClass] = useState('');
  const [classes,     setClasses]     = useState([]);
  const [loading,     setLoading]     = useState(false);
  const [selDesign,   setSelDesign]   = useState('h1');
  const [selTheme,    setSelTheme]    = useState('indigo');
  const [selected,    setSelected]    = useState(new Set());
  const [school,      setSchool]      = useState({});
  const [previewStu,  setPreviewStu]  = useState(null);

  useEffect(() => {
    try { setSchool(JSON.parse(localStorage.getItem('school_settings'))||{}); } catch {}
    schoolAPI.getClasses().then(r=>setClasses(r.data.data||[])).catch(()=>{});
  }, []);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const res = await studentAPI.getAll({ limit:200, search:search||undefined, className:filterClass||undefined });
      const data = res.data.data||[];
      setStudents(data);
      if (!previewStu && data.length) setPreviewStu(data[0]);
    } catch { setStudents([]); } finally { setLoading(false); }
  }, [search, filterClass]);

  useEffect(() => { load(); }, [load]);

  const toggleSel = s => { setPreviewStu(s); setSelected(prev=>{const n=new Set(prev);n.has(s.id)?n.delete(s.id):n.add(s.id);return n;}); };
  const design = DESIGNS.find(d=>d.id===selDesign)||DESIGNS[0];
  const CardComp = design.C;
  const selStudents = students.filter(s=>selected.has(s.id));
  const inp = {padding:'9px 12px',border:'1.5px solid #E5E7EB',borderRadius:9,fontSize:13,outline:'none',fontFamily:'inherit',background:'#fff',boxSizing:'border-box'};

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:16}}>
        <div>
          <h2 style={{fontSize:20,fontWeight:700,color:'#111827'}}>ID Card Generator</h2>
          <p style={{fontSize:12,color:'#6B7280',marginTop:2}}>{students.length} students · {selected.size} selected</p>
        </div>
        <div style={{display:'flex',gap:10}}>
          {previewStu && <button onClick={()=>printCards([previewStu],design,selTheme,school)} style={{padding:'10px 18px',border:'1.5px solid #1E1B4B',background:'#fff',color:'#1E1B4B',borderRadius:10,fontSize:13,fontWeight:600,cursor:'pointer'}}>🖨️ Preview</button>}
          {selected.size>0 && <button onClick={()=>printCards(selStudents,design,selTheme,school)} style={{padding:'10px 20px',background:'#1E1B4B',color:'#fff',border:'none',borderRadius:10,fontSize:13,fontWeight:700,cursor:'pointer'}}>🖨️ Print {selected.size}</button>}
        </div>
      </div>

      <div style={{display:'grid',gridTemplateColumns:'300px 1fr',gap:16}}>
        <div style={{display:'flex',flexDirection:'column',gap:12}}>
          {/* Design */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:'#111827'}}>Card Design</div>
            {[{label:'Horizontal',o:'H'},{label:'Vertical',o:'V'}].map(({label,o})=>(
              <div key={o} style={{marginBottom:8}}>
                <div style={{fontSize:10,fontWeight:700,color:'#9CA3AF',textTransform:'uppercase',marginBottom:5}}>{label}</div>
                <div style={{display:'flex',gap:5}}>
                  {DESIGNS.filter(d=>d.orientation===o).map(d=>(
                    <button key={d.id} onClick={()=>setSelDesign(d.id)}
                      style={{flex:1,padding:'7px 4px',border:'1.5px solid '+(selDesign===d.id?'#1E1B4B':'#E5E7EB'),borderRadius:8,background:selDesign===d.id?'#EDE9F8':'#fff',fontSize:9.5,fontWeight:selDesign===d.id?700:400,cursor:'pointer',color:selDesign===d.id?'#1E1B4B':'#374151'}}>
                      {d.label}
                    </button>
                  ))}
                </div>
              </div>
            ))}
          </div>
          {/* Theme */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:'#111827'}}>Color Theme</div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6}}>
              {Object.entries(THEMES).map(([key,t])=>(
                <button key={key} onClick={()=>setSelTheme(key)}
                  style={{padding:'8px',border:'2px solid '+(selTheme===key?t.p1:'#E5E7EB'),borderRadius:9,background:selTheme===key?t.bg:'#fff',cursor:'pointer',display:'flex',alignItems:'center',gap:8}}>
                  <div style={{width:16,height:16,borderRadius:4,background:t.p1,flexShrink:0}}/>
                  <span style={{fontSize:10,fontWeight:700,color:selTheme===key?t.p1:'#374151'}}>{t.name}</span>
                </button>
              ))}
            </div>
          </div>
          {/* Students */}
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:'#111827'}}>Students</div>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search..." style={{...inp,width:'100%',marginBottom:8}}/>
            <select value={filterClass} onChange={e=>setFilterClass(e.target.value)} style={{...inp,width:'100%',marginBottom:8}}>
              <option value="">All Classes</option>
              {classes.map(c=><option key={c.id} value={c.name}>{c.name}</option>)}
            </select>
            <div style={{display:'flex',gap:6,marginBottom:8}}>
              <button onClick={()=>setSelected(new Set(students.map(s=>s.id)))} style={{flex:1,padding:'6px',border:'1px solid #E5E7EB',borderRadius:7,background:'#F9FAFB',fontSize:11,cursor:'pointer',fontWeight:600}}>All</button>
              <button onClick={()=>setSelected(new Set())} style={{flex:1,padding:'6px',border:'1px solid #E5E7EB',borderRadius:7,background:'#F9FAFB',fontSize:11,cursor:'pointer',fontWeight:600}}>Clear</button>
            </div>
            <div style={{maxHeight:240,overflowY:'auto',border:'1px solid #F3F4F6',borderRadius:8}}>
              {loading ? <div style={{padding:16,textAlign:'center',color:'#9CA3AF',fontSize:12}}>Loading...</div>
                : students.map(s=>(
                  <div key={s.id} onClick={()=>toggleSel(s)}
                    style={{display:'flex',alignItems:'center',gap:8,padding:'7px 10px',borderBottom:'0.5px solid #F9FAFB',cursor:'pointer',background:selected.has(s.id)?'#EDE9F8':previewStu?.id===s.id?'#F5F3FF':'#fff'}}>
                    <input type="checkbox" checked={selected.has(s.id)} onChange={()=>{}} style={{accentColor:'#1E1B4B',flexShrink:0}}/>
                    {s.photo_url
                      ? <img src={s.photo_url} style={{width:26,height:26,borderRadius:'50%',objectFit:'cover',flexShrink:0}}/>
                      : <div style={{width:26,height:26,borderRadius:'50%',background:'#EDE9F8',display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:700,color:'#1E1B4B',flexShrink:0}}>{(s.first_name||'?')[0]}</div>}
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:11,fontWeight:600,color:'#111827',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{s.first_name} {s.last_name||''}</div>
                      <div style={{fontSize:9,color:'#9CA3AF'}}>{s.admission_no} · {s.class_name||'—'}</div>
                    </div>
                  </div>
                ))}
            </div>
          </div>
        </div>

        {/* Preview */}
        <div>
          <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:20}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:3,color:'#111827',display:'flex',justifyContent:'space-between'}}>
              <span>{design.label} — {design.sub}</span>
              <span style={{fontSize:11,color:'#9CA3AF',fontWeight:400}}>{design.orientation==='H'?'Landscape':'Portrait'}</span>
            </div>
            <div style={{fontSize:11,color:'#9CA3AF',marginBottom:16}}>Click a student to preview</div>
            <div style={{display:'flex',justifyContent:'center',padding:24,background:'#F8FAFC',borderRadius:12,border:'1px solid #E5E7EB'}}>
              <CardComp stu={previewStu} th={selTheme} sch={school}/>
            </div>
          </div>

          {selected.size > 0 && (
            <div style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:14,padding:14,marginTop:12}}>
              <div style={{fontWeight:700,fontSize:13,marginBottom:10,color:'#111827'}}>Selected ({selected.size})</div>
              <div style={{display:'flex',gap:8,flexWrap:'wrap',overflow:'hidden'}}>
                {selStudents.slice(0,8).map(s=>{
                  const sc = design.orientation==='V' ? 0.34 : 0.36;
                  const mr = design.orientation==='V' ? -140 : -220;
                  const mb = design.orientation==='V' ? -218 : -138;
                  return (
                    <div key={s.id} style={{transform:`scale(${sc})`,transformOrigin:'top left',flexShrink:0,marginRight:mr,marginBottom:mb}}>
                      <CardComp stu={s} th={selTheme} sch={school}/>
                    </div>
                  );
                })}
                {selStudents.length > 8 && <div style={{display:'flex',alignItems:'center',justifyContent:'center',width:70,height:46,background:'#F9FAFB',borderRadius:8,fontSize:12,color:'#6B7280',fontWeight:600,flexShrink:0}}>+{selStudents.length-8}</div>}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
